import pandas as pd
import matplotlib.pyplot as plt
from stravalib import Client
from polar import PolarFlow
from myfitnesspal import MyFitnessPal

class WorkoutTracker:
    def __init__(self, strava_token, polar_token, myfitnesspal_token):
        self.strava_client = Client(access_token=strava_token)
        self.polar_flow = PolarFlow(polar_token)
        self.myfitnesspal = MyFitnessPal(myfitnesspal_token)

    def get_strava_workouts(self):
        activities = self.strava_client.get_activities(limit=100)
        workouts = []
        for activity in activities:
            workout = {
                'date': activity.start_date,
                'type': activity.type,
                'distance': activity.distance.get_num(),
                'time': activity.elapsed_time.total_seconds(),
                'heart_rate': activity.heart_rate.get_num()
            }
            workouts.append(workout)
        return pd.DataFrame(workouts)

    def get_polar_workouts(self):
        workouts = self.polar_flow.get_workouts()
        data = []
        for workout in workouts:
            data.append({
                'date': workout['date'],
                'type': workout['type'],
                'distance': workout['distance'],
                'time': workout['duration'],
                'heart_rate': workout['heart_rate']
            })
        return pd.DataFrame(data)

    def get_myfitnesspal_nutrition(self):
        nutrition = self.myfitnesspal.get_nutrition()
        data = []
        for entry in nutrition:
            data.append({
                'date': entry['date'],
                'calories': entry['calories'],
                'protein': entry['protein'],
                'carbs': entry['carbs'],
                'fat': entry['fat']
            })
        return pd.DataFrame(data)

    def aggregate_heart_rate(self, workouts):
        heart_rate_data = []
        for workout in workouts:
            heart_rate = workout['heart_rate']
            if heart_rate:
                zones = {
                    'low': 0,
                    'moderate': 0,
                    'high': 0,
                    'very_high': 0
                }
                for zone in zones:
                    if zone == 'low' and heart_rate < 120:
                        zones[zone] += workout['time']
                    elif zone == 'moderate' and 120 <= heart_rate < 140:
                        zones[zone] += workout['time']
                    elif zone == 'high' and 140 <= heart_rate < 160:
                        zones[zone] += workout['time']
                    elif zone == 'very_high' and heart_rate >= 160:
                        zones[zone] += workout['time']
                heart_rate_data.append({
                    'date': workout['date'],
                    'low': zones['low'],
                    'moderate': zones['moderate'],
                    'high': zones['high'],
                    'very_high': zones['very_high']
                })
        return pd.DataFrame(heart_rate_data)

    def plot_progress(self, workouts, metric):
        if metric == 'pace':
            workouts['pace'] = workouts['time'] / workouts['distance']
            plt.plot(workouts['date'], workouts['pace'])
        elif metric == 'mileage':
            plt.plot(workouts['date'], workouts['distance'])
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.show()

def main():
    strava_token = 'your_strava_token'
    polar_token = 'your_polar_token'
    myfitnesspal_token = 'your_myfitnesspal_token'
    tracker = WorkoutTracker(strava_token, polar_token, myfitnesspal_token)
    strava_workouts = tracker.get_strava_workouts()
    polar_workouts = tracker.get_polar_workouts()
    myfitnesspal_nutrition = tracker.get_myfitnesspal_nutrition()
    workouts = pd.concat([strava_workouts, polar_workouts])
    heart_rate_data = tracker.aggregate_heart_rate(workouts)
    print(heart_rate_data)
    tracker.plot_progress(workouts, 'pace')
    tracker.plot_progress(workouts, 'mileage')

if __name__ == '__main__':
    main()

