            y = [workout['distance'] for workout in self.workouts]
        plt.plot(x, y)
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.show()

    def dashboard(self):
        print('Workouts:')
        for workout in self.workouts:
            print(f"Date: {workout['date']}, Type: {workout['type']}, Distance: {workout['distance']}, Time: {workout['time']}, Heart Rate: {workout['heart_rate']}")
