import pandas as pd
import matplotlib.pyplot as plt
from datetime import datetime

class FitnessDashboard:
    def __init__(self):
        self.workouts = []
        self.mileage = []
        self.heart_rate = []
        self.time = []

    def add_workout(self, date, workout_type, distance, heart_rate, time):
        self.workouts.append({'date': date, 'workout_type': workout_type, 'distance': distance, 'heart_rate': heart_rate, 'time': time})
        self.mileage.append(distance)
        self.heart_rate.append(heart_rate)
        self.time.append(time)

    def view_workouts(self):
        for workout in self.workouts:
            print(f"Date: {workout['date']}, Workout Type: {workout['workout_type']}, Distance: {workout['distance']} miles, Heart Rate: {workout['heart_rate']} bpm, Time: {workout['time']} minutes")

    def view_mileage(self):
        print(f"Total Mileage: {sum(self.mileage)} miles")

    def view_heart_rate(self):
        print(f"Average Heart Rate: {sum(self.heart_rate) / len(self.heart_rate)} bpm")

    def view_time(self):
        print(f"Total Time: {sum(self.time)} minutes")

    def graph_progress(self, by):
        if by == 'pace':
            pace = [workout['time'] / workout['distance'] for workout in self.workouts]
            plt.plot([workout['date'] for workout in self.workouts], pace)
            plt.xlabel('Date')
            plt.ylabel('Pace (minutes per mile)')
            plt.title('Progress by Pace')
        elif by == 'mileage':
            plt.plot([workout['date'] for workout in self.workouts], self.mileage)
            plt.xlabel('Date')
            plt.ylabel('Mileage (miles)')
            plt.title('Progress by Mileage')
        plt.show()

def main():
    dashboard = FitnessDashboard()
    while True:
        print("1. Add Workout")
        print("2. View Workouts")
        print("3. View Mileage")
        print("4. View Heart Rate")
        print("5. View Time")
        print("6. Graph Progress")
