        if choice == '1':
            date = input("Enter date (YYYY-MM-DD): ")
            workout_type = input("Enter workout type: ")
            distance = float(input("Enter distance (miles): "))
            heart_rate = float(input("Enter heart rate (bpm): "))
            time = float(input("Enter time (minutes): "))
            dashboard.add_workout(date, workout_type, distance, heart_rate, time)
        elif choice == '2':
            dashboard.view_workouts()
        elif choice == '3':
            dashboard.view_mileage()
        elif choice == '4':
