            print(f"Date: {workout['date']}, Activity: {workout['activity']}, Duration: {workout['duration']}, Distance: {workout['distance']}, Calories: {workout['calories']}, Heart Rate: {workout['heart_rate']}")

    def view_workouts_by_activity(self):
        activities = {}
        for workout in self.workouts:
            if workout['activity'] not in activities:
                activities[workout['activity']] = []
            activities[workout['activity']].append(workout)
