def add_todo(app, todo):
    try:
        app["todos"].append(todo)
    except KeyError:
        app["todos"] = [todo]

def remove_todo(app, todo_id):
    try:
        app["todos"].pop(todo_id)
    except (KeyError, IndexError):
        pass

def view_todos(app):
    try:
        return app["todos"]
    except KeyError:
        return []

def save_app(app, filename):
    import pickle
    with open(filename, "wb") as file:
        pickle.dump(app, file)

def load_app(filename):
    import pickle
    try:
        with open(filename, "rb") as file:
            return pickle.load(file)
    except FileNotFoundError:
        return {}

